using System;
using System.Threading;
using System.Threading.Tasks;

/// <summary>
/// .NET 8 migration of BackgroundProcessor.
/// Key changes from .NET Framework:
///   1. Thread.Abort() / ResetAbort() removed — throws PlatformNotSupportedException
///   2. Replaced with CancellationToken cooperative cancellation
///   3. Uses Task instead of raw Thread for better resource management
///   4. Implements IDisposable for deterministic cleanup
/// </summary>
public class BackgroundProcessor : IDisposable
{
    private Task? _workerTask;
    private CancellationTokenSource? _cts;
    private bool _disposed;

    public void Start()
    {
        ObjectDisposedException.ThrowIf(_disposed, this);

        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _workerTask = Task.Run(() => ProcessLoop(token), token);
    }

    private void ProcessLoop(CancellationToken token)
    {
        while (!token.IsCancellationRequested)
        {
            try
            {
                // Pass the token to blocking calls so they can be interrupted
                var item = GetNextItem(token);
                ProcessItem(item, token);
            }
            catch (OperationCanceledException) when (token.IsCancellationRequested)
            {
                // Cooperative cancellation — replaces ThreadAbortException handling.
                // Unlike Thread.Abort(), this does NOT auto-rethrow, so no
                // ResetAbort() equivalent is needed.
                RollbackCurrentTransaction();
                break; // exit the loop cleanly
            }
            finally
            {
                FlushBuffers();
            }
        }
    }

    public void Stop()
    {
        if (_cts is null || _workerTask is null)
            return;

        // Signal cancellation (replaces _running = false)
        _cts.Cancel();

        try
        {
            // Wait with a timeout instead of Thread.Sleep + Abort
            if (!_workerTask.Wait(TimeSpan.FromSeconds(2)))
            {
                // Task didn't finish in time — but we CANNOT force-kill it.
                // Log a warning; the task will finish when the next
                // cancellation-aware call checks the token.
                Console.Error.WriteLine(
                    "BackgroundProcessor did not stop within the timeout.");
            }
        }
        catch (AggregateException ex) when (ex.InnerException is OperationCanceledException)
        {
            // Expected when the task observes cancellation via token
        }
    }

    public void Dispose()
    {
        if (_disposed) return;
        _disposed = true;

        Stop();
        _cts?.Dispose();
        _workerTask?.Dispose();
    }

    // --- Stub methods — update signatures to accept CancellationToken ---

    private object GetNextItem(CancellationToken token)
    {
        // PITFALL: If this was a blocking call (e.g., BlockingCollection.Take),
        // use the overload that accepts a CancellationToken so it unblocks
        // immediately on cancellation instead of hanging forever.
        //
        // Example: return _queue.Take(token);
        throw new NotImplementedException();
    }

    private void ProcessItem(object item, CancellationToken token)
    {
        // Check token periodically in long-running work:
        //   token.ThrowIfCancellationRequested();
        throw new NotImplementedException();
    }

    private void RollbackCurrentTransaction() { }
    private void FlushBuffers() { }
}

